namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    [TestClass]
    public sealed class CreateOrder
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void ReturnsOrder_WithCorrectCustomerId()
        {
            var items = CreateItems(("Widget", 10.00m, 2));

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual("cust-1", order.CustomerId);
        }

        [TestMethod]
        public void ReturnsOrder_WithAssignedId()
        {
            var items = CreateItems(("Widget", 10.00m, 1));

            var order = _sut.CreateOrder("cust-1", items);

            Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        }

        [TestMethod]
        public void CalculatesTotal_ForSingleItem()
        {
            var items = CreateItems(("Widget", 5.50m, 3));

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual(16.50m, order.Total);
        }

        [TestMethod]
        public void CalculatesTotal_ForMultipleItems()
        {
            var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual(45.00m, order.Total);
        }

        [TestMethod]
        public void SetsCreatedAtToUtcNow()
        {
            var before = DateTime.UtcNow;
            var items = CreateItems(("Widget", 10.00m, 1));

            var order = _sut.CreateOrder("cust-1", items);

            var after = DateTime.UtcNow;
            Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
        }

        [TestMethod]
        public void StoresItems_InOrder()
        {
            var items = CreateItems(("Widget", 10.00m, 1), ("Gadget", 20.00m, 2));

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual(2, order.Items.Count);
            Assert.AreEqual("Widget", order.Items[0].ProductName);
            Assert.AreEqual("Gadget", order.Items[1].ProductName);
        }

        [TestMethod]
        public void ThrowsArgumentNullException_WhenCustomerIdIsNull()
        {
            var items = CreateItems(("Widget", 10.00m, 1));

            Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        }

        [TestMethod]
        public void ThrowsArgumentNullException_WhenItemsIsNull()
        {
            Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
        }

        [TestMethod]
        public void ThrowsInvalidOperationException_WhenItemsIsEmpty()
        {
            Assert.ThrowsExactly<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
        }

        private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
            items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();
    }

    [TestClass]
    public sealed class GetOrder
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void ReturnsOrder_WhenItExists()
        {
            var items = CreateItems(("Widget", 10.00m, 1));
            var created = _sut.CreateOrder("cust-1", items);

            var result = _sut.GetOrder(created.Id);

            Assert.IsNotNull(result);
            Assert.AreEqual(created.Id, result.Id);
        }

        [TestMethod]
        public void ReturnsNull_WhenOrderDoesNotExist()
        {
            var result = _sut.GetOrder("nonexistent");

            Assert.IsNull(result);
        }

        private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
            items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();
    }

    [TestClass]
    public sealed class GetOrdersByCustomer
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void ReturnsAllOrders_ForGivenCustomer()
        {
            var items = CreateItems(("Widget", 10.00m, 1));
            _sut.CreateOrder("cust-1", items);
            _sut.CreateOrder("cust-1", items);
            _sut.CreateOrder("cust-2", items);

            var result = _sut.GetOrdersByCustomer("cust-1");

            Assert.AreEqual(2, result.Count);
        }

        [TestMethod]
        public void ReturnsEmptyList_WhenCustomerHasNoOrders()
        {
            var result = _sut.GetOrdersByCustomer("nonexistent");

            Assert.AreEqual(0, result.Count);
        }

        [TestMethod]
        public void DoesNotReturnOrders_FromOtherCustomers()
        {
            var items = CreateItems(("Widget", 10.00m, 1));
            _sut.CreateOrder("cust-1", items);
            _sut.CreateOrder("cust-2", items);

            var result = _sut.GetOrdersByCustomer("cust-1");

            Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
        }

        private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
            items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();
    }
}

